@startuml
skinparam classAttributeIconSize 0

class "User" {
}

interface Prototype <<I>> {
    + create_clone() : Object;
}

class ConcretePrototype {
    - prototype_id: String = "";

    + set_prototype(id) 
        -> void

    # clone(): Self<ConcretePrototype> 

    ~ _clone_impl(prototype): Result<Self<ConcretePrototype>, Error>;
}


' Relationships
note right of User::create_new_user\n(user_name)\n-> Option<User>\nThe user creates new users by cloning itself.\nnote left of Prototype::\nA trait for objects which can be cloned to produce an identical copy.\nnote bottom of ConcretePrototype::set_prototype()\nSets the ID used in `Debug` output. This allows us to differentiate instances from each other,\neven if they have exactly same data inside them at runtime since IDs are unique across all clones ever created.' 

@enduml
